import React, { createContext, useState, useContext, useEffect } from 'react';
import { authAPI } from '../services/api';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // 1. Session Re-Hydration
  useEffect(() => {
    const token = localStorage.getItem('accessToken');
    if (token) {
      authAPI.getMe().then(res => setCurrentUser(res.data)).catch(() => setCurrentUser(null)).finally(() => setLoading(false));
    } else {
      setLoading(false);
    }

    const handleLogout = () => setCurrentUser(null);
    window.addEventListener('auth:logout', handleLogout);
    return () => window.removeEventListener('auth:logout', handleLogout);
  }, []);

  // 2. Authentication Logic
  const login = async (credentials) => {
    const res = await authAPI.login(credentials);
    if (res.data.accessToken) localStorage.setItem('accessToken', res.data.accessToken);
    setCurrentUser(res.data.user);
  };

  const register = async (userData) => {
    const res = await authAPI.register(userData);
    if (res.data.accessToken) localStorage.setItem('accessToken', res.data.accessToken);
    setCurrentUser(res.data.user);
  };

  const logout = async () => {
    await authAPI.logout().catch(console.error);
    setCurrentUser(null);
  };

  const value = { currentUser, login, logout, register, isAuthenticated: !!currentUser };

  if (loading) return <div className="text-center py-5"><div className="spinner-border text-primary"></div></div>;

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => useContext(AuthContext);
